// Scans public/ for localized asset variants and writes a manifest the runtime
// resolver (src/i18n/assets.ts) consults to decide whether a translated asset
// exists for the active locale, falling back to English otherwise.
//
// Localized files live under a locale folder inserted after the first path
// segment, e.g. the English "/screenshots/app/x.png" is translated by adding
// "/screenshots/pt/app/x.png". This scanner records the ENGLISH base path per
// locale so the resolver can look it up by the path used in code.
//
// Runs at build time (see package.json). The generated file is committed so
// dev/typecheck work without running the scanner first.

import {
  readdirSync,
  statSync,
  writeFileSync,
  existsSync,
  readFileSync,
} from "fs";
import { join, dirname } from "path";
import { fileURLToPath } from "url";

const __dirname = dirname(fileURLToPath(import.meta.url));
const ROOT = join(__dirname, "..");
const PUBLIC = join(ROOT, "public");
const OUT = join(ROOT, "src/i18n/localized-assets.generated.ts");

// Non-default locales only; English is the base and never a subfolder.
const LOCALES = ["pt", "es"];
// Top-level public folders that hold app depictions worth localizing.
const SCAN_DIRS = ["screenshots", "videos"];

function walk(dir) {
  if (!existsSync(dir)) return [];
  const out = [];
  for (const name of readdirSync(dir)) {
    const full = join(dir, name);
    if (statSync(full).isDirectory()) out.push(...walk(full));
    else out.push(full);
  }
  return out;
}

const entries = new Set();
for (const top of SCAN_DIRS) {
  for (const file of walk(join(PUBLIC, top))) {
    const rel = file.slice(PUBLIC.length + 1).split(/[/\\]/);
    // rel = [<top>, <maybe-locale>, ...rest, <file>]
    const locale = rel[1];
    if (!LOCALES.includes(locale)) continue;
    const basePath = "/" + [rel[0], ...rel.slice(2)].join("/");
    entries.add(`${locale}|${basePath}`);
  }
}

const sorted = [...entries].sort();
const body = `// AUTO-GENERATED by scripts/generate-asset-manifest.mjs. Do not edit by hand.
// Run \`npm run manifest:assets\` (or a build) to regenerate.
// Each entry is "<locale>|<english base path>" for a localized asset that exists
// under public/. The resolver in ./assets.ts uses it to decide fallback.

export const LOCALIZED_ASSETS: ReadonlySet<string> = new Set([
${sorted.map((e) => `  ${JSON.stringify(e)},`).join("\n")}
]);
`;

// Only write when changed so builds stay idempotent and diffs stay quiet.
const prev = existsSync(OUT) ? readFileSync(OUT, "utf-8") : "";
if (prev !== body) {
  writeFileSync(OUT, body);
  console.log(`asset manifest: ${sorted.length} localized asset(s)`);
} else {
  console.log(
    `asset manifest: up to date (${sorted.length} localized asset(s))`,
  );
}
